parameters.jsCode:
const retro = $('Normalise Retro Data').first().json;
let analysis;
try { analysis = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); } catch { analysis = {}; }
return [{ json: { retro_id: retro.retro_id, sprint: retro.sprint, team: retro.team, date: retro.date, participants: retro.participants, processed_at: new Date().toISOString(), ...analysis } }];

parameters.message:
Sprint {{ $json.sprint }} Retrospective — {{ $json.date }}
Team: {{ $json.team }} | Health: {{ $json.team_health_signal?.toUpperCase() || '?' }}

SUMMARY
{{ $json.summary }}

✅ WENT WELL
{{ ($json.themes_went_well||[]).map(t => `${t.theme}:\n${(t.items||[]).map(i=>`  • ${i}`).join('\n')}`).join('\n\n') }}

⚠️ TO IMPROVE
{{ ($json.themes_to_improve||[]).map(t => `${t.theme}${t.systemic?' [SYSTEMIC]':''}:\n${(t.items||[]).map(i=>`  • ${i}`).join('\n')}`).join('\n\n') }}

ACTION ITEMS
{{ ($json.action_items_structured||[]).map(a => `• [${a.priority}] ${a.action}${a.owner?' → '+a.owner:''}${a.due?' by '+a.due:''}`).join('\n') || 'None.' }}

RECOMMENDED EXPERIMENTS
{{ ($json.recommended_experiments||[]).map(e=>`→ ${e}`).join('\n') || 'None.' }}
